import{_ as i,o as e,c as t,a as o}from"./app.23d84491.js";const g=JSON.parse('{"title":"Yoahtl v. iOminous, Jan 2018","description":"","frontmatter":{},"headers":[{"level":2,"title":"Charges","slug":"charges","link":"#charges","children":[]},{"level":2,"title":"Plea","slug":"plea","link":"#plea","children":[]},{"level":2,"title":"Proceedings","slug":"proceedings","link":"#proceedings","children":[]},{"level":2,"title":"Outcome","slug":"outcome","link":"#outcome","children":[]},{"level":2,"title":"Appeals Outcome","slug":"appeals-outcome","link":"#appeals-outcome","children":[]}],"relativePath":"government/court-cases-precedents/yoahtl_v_iominous_jan_2018.md","lastUpdated":1666055355000}'),a={name:"government/court-cases-precedents/yoahtl_v_iominous_jan_2018.md"},n=o('<h1 id="yoahtl-v-iominous-jan-2018" tabindex="-1">Yoahtl v. iOminous, Jan 2018 <a class="header-anchor" href="#yoahtl-v-iominous-jan-2018" aria-hidden="true">#</a></h1><p><strong>Judge</strong>: Mightyoddish</p><p><strong>Date</strong>: 29th January 2018</p><h2 id="charges" tabindex="-1">Charges <a class="header-anchor" href="#charges" aria-hidden="true">#</a></h2><p>Disorderly conduct.</p><h2 id="plea" tabindex="-1">Plea <a class="header-anchor" href="#plea" aria-hidden="true">#</a></h2><p>Not guilty.</p><h2 id="proceedings" tabindex="-1">Proceedings <a class="header-anchor" href="#proceedings" aria-hidden="true">#</a></h2><ul><li><p>Modshot claims iOminous threw an invisibility potion at American_Grandma and himself. He then informed iOminous that it was illegal to be invisible. iOminous proceeds to throw invisibility potions on people and adk people if they want to be invisible.</p></li><li><p>iOminous claims Modshot has a grudge against him. He then claims there\u2019s no clarity around Yoahtlan laws. Furthermore he claims the invisibility potions were gifts.</p></li><li><p>Modshot states iOminous being a potion merchant is no excuse for violating law and that throwing potions on people does not constitute giving them a gift.</p></li><li><p>Sparkelly confirmed iOminous threw an invisibility potion at him after being prompted whether he wanted to be invisible.</p></li><li><p>Oddish clarifies that being invisible without declaration is illegal within Yoahtl and that is the law iOminous is accused of breaking.</p></li><li><p>Modshot says iOminous is framing people with his actions.</p></li><li><p>American_Grandma testifies she didn\u2019t ask to be invisible an iOminous threw potions at her and others.</p></li><li><p>(Proceedings then derail onto a tangent about how difficult it is to find Yoahtlan laws codified)</p></li><li><p>TheOrangeWizard takes over the prosecution from Modshot, supplying the following summary:</p><ul><li>Disorderly conduct for throwing invisibility splash potions on other parties</li><li>You were made aware that being invisible without announcing it was unacceptable</li><li>You continued to throw invisibility potions</li><li>In the opinion of the prosecution, this is a deliberate attempt to flaunt the law. You were aware of the nature of invisibility and chose to push the boundaries anyway.</li></ul></li><li><p>iOminous states it is the responsibility of Government to codify and ensure people are aware of the laws and continues to deny any wrong doing.</p></li></ul><h2 id="outcome" tabindex="-1">Outcome <a class="header-anchor" href="#outcome" aria-hidden="true">#</a></h2><p>iOminous is found guilty of disorderly conduct and the misuse of invisibility potions without declaration and consent of other parties. He is sentenced to community service: digging the vault hole for 3 hours.</p><h2 id="appeals-outcome" tabindex="-1">Appeals Outcome <a class="header-anchor" href="#appeals-outcome" aria-hidden="true">#</a></h2><p>iOminous appeals to Alcuahtl bgbba, who uphold&#39;s Mightyoddish&#39;s judgement.</p>',13),s=[n];function l(r,h,d,c,p,u){return e(),t("div",null,s)}const f=i(a,[["render",l]]);export{g as __pageData,f as default};
